document.addEventListener('DOMContentLoaded', () => {
    
    // --- Size Selection Logic ---
    const sizeBtns = document.querySelectorAll('.size-btn');
    const selectedSizeLabel = document.getElementById('selected-size');

    sizeBtns.forEach(btn => {
        btn.addEventListener('click', () => {
            // Remove active from all
            sizeBtns.forEach(b => b.classList.remove('active'));
            // Add to clicked
            btn.classList.add('active');
            // Update label
            selectedSizeLabel.textContent = btn.textContent;
        });
    });

    // --- Size Guide Modal ---
    const modal = document.getElementById('size-modal');
    const openBtn = document.getElementById('open-size-guide');
    const closeBtn = document.querySelector('.close-modal');

    openBtn.addEventListener('click', () => {
        modal.classList.add('open');
    });

    closeBtn.addEventListener('click', () => {
        modal.classList.remove('open');
    });

    // Close on outside click
    modal.addEventListener('click', (e) => {
        if (e.target === modal) {
            modal.classList.remove('open');
        }
    });

    // --- Sticky Mobile Bar ---
    const stickyBar = document.getElementById('sticky-bar');
    const addToCartBtn = document.querySelector('.add-to-cart-btn');

    // Only enable on small screens potentially, or just by scroll
    window.addEventListener('scroll', () => {
        const btnPosition = addToCartBtn.getBoundingClientRect().bottom;
        
        // If main button is scrolled out of view (negative top usually implies it's above viewport)
        // A simple heuristic: if we've scrolled past the first 400px
        if (window.scrollY > 400) {
            stickyBar.classList.add('visible');
        } else {
            stickyBar.classList.remove('visible');
        }
    });

    // Sync sticky button with main button (simulate add to cart)
    const stickyBtn = document.querySelector('.sticky-btn');
    stickyBtn.addEventListener('click', () => {
        alert('Added to cart!');
        // Here you would typically trigger the form submit or AJAX cart add
    });

    addToCartBtn.addEventListener('click', () => {
        alert('Added to cart!');
    });
});

import React, { useState } from 'react';
import { Outlet, NavLink, useNavigate } from 'react-router-dom';
import { supabase } from '../../supabaseClient';
import { motion, AnimatePresence } from 'framer-motion';
import { LayoutDashboard, Package, CreditCard, LogOut, Menu, X } from 'lucide-react';

const AdminLayout = () => {
    const [sidebarOpen, setSidebarOpen] = useState(true);
    const navigate = useNavigate();

    const handleLogout = async () => {
        await supabase.auth.signOut();
        navigate('/admin/login');
    };

    const navItems = [
        { path: '/admin/dashboard', icon: LayoutDashboard, label: 'Dashboard' },
        { path: '/admin/products', icon: Package, label: 'Products' },
        { path: '/admin/transactions', icon: CreditCard, label: 'Transactions' },
    ];

    return (
        <div className="admin-layout" style={{ display: 'flex', height: '100vh', background: 'var(--bg-color)', color: 'var(--text-primary)', overflow: 'hidden' }}>
            <button
                className="mobile-toggle"
                onClick={() => setSidebarOpen(!sidebarOpen)}
                style={{ position: 'fixed', top: '20px', left: '20px', zIndex: 100, background: 'rgba(0,0,0,0.5)', border: '1px solid var(--accent-color)', color: 'var(--text-primary)', cursor: 'pointer', padding: '10px', borderRadius: '8px', display: 'none' }}
            >
                {sidebarOpen ? <X size={24} /> : <Menu size={24} />}
            </button>

            <AnimatePresence>
                {sidebarOpen && (
                    <motion.div
                        initial={{ x: -250 }}
                        animate={{ x: 0 }}
                        exit={{ x: -250 }}
                        className="admin-sidebar glass-panel"
                        style={{
                            width: '250px',
                            height: '100%',
                            background: 'rgba(255, 255, 255, 0.03)',
                            borderRight: '1px solid rgba(255,255,255,0.05)',
                            backdropFilter: 'blur(10px)',
                            display: 'flex',
                            flexDirection: 'column',
                            padding: '30px 20px',
                            zIndex: 50
                        }}
                    >
                        <div style={{ marginBottom: '50px', display: 'flex', alignItems: 'center', gap: '10px' }}>
                            <div style={{ width: '10px', height: '10px', background: 'var(--accent-color)', borderRadius: '50%', boxShadow: '0 0 10px var(--accent-color)' }}></div>
                            <h2 style={{ fontFamily: 'var(--font-heading)', margin: 0, fontSize: '1.2rem', letterSpacing: '2px', color: 'var(--text-primary)' }}>SYS_ADMIN</h2>
                        </div>

                        <nav style={{ display: 'flex', flexDirection: 'column', gap: '15px', flex: 1 }}>
                            {navItems.map((item) => (
                                <NavLink
                                    key={item.path}
                                    to={item.path}
                                    style={({ isActive }) => ({
                                        display: 'flex',
                                        alignItems: 'center',
                                        gap: '15px',
                                        padding: '12px 15px',
                                        borderRadius: '8px',
                                        textDecoration: 'none',
                                        color: isActive ? '#000' : 'var(--text-secondary)',
                                        background: isActive ? 'var(--accent-color)' : 'transparent',
                                        fontWeight: isActive ? 'bold' : 'normal',
                                        transition: 'all 0.3s',
                                        boxShadow: isActive ? '0 0 15px rgba(0, 240, 255, 0.3)' : 'none'
                                    })}
                                >
                                    <item.icon size={20} />
                                    <span>{item.label}</span>
                                </NavLink>
                            ))}
                        </nav>

                        <button
                            onClick={handleLogout}
                            style={{
                                display: 'flex',
                                alignItems: 'center',
                                gap: '15px',
                                padding: '12px 15px',
                                background: 'transparent',
                                border: '1px solid rgba(255,255,255,0.1)',
                                color: 'var(--text-primary)',
                                borderRadius: '8px',
                                cursor: 'pointer',
                                transition: 'all 0.3s',
                                marginTop: 'auto'
                            }}
                            onMouseOver={(e) => {
                                e.currentTarget.style.background = 'rgba(255, 68, 68, 0.1)';
                                e.currentTarget.style.borderColor = '#ff4444';
                                e.currentTarget.style.color = '#ff4444';
                            }}
                            onMouseOut={(e) => {
                                e.currentTarget.style.background = 'transparent';
                                e.currentTarget.style.borderColor = 'rgba(255,255,255,0.1)';
                                e.currentTarget.style.color = 'var(--text-primary)';
                            }}
                        >
                            <LogOut size={20} />
                            <span>LOGOUT</span>
                        </button>
                    </motion.div>
                )}
            </AnimatePresence>

            <div style={{ flex: 1, overflowY: 'auto', padding: '40px', position: 'relative' }}>
                <Outlet />
            </div>

            <style>{`
        @media (max-width: 768px) {
          .mobile-toggle { display: block !important; }
          .admin-sidebar { position: fixed; }
        }
      `}</style>
        </div>
    );
};

export default AdminLayout;

import React, { useState } from 'react';
import { supabase } from '../../supabaseClient';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';

const AdminLogin = () => {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');
    const navigate = useNavigate();

    const handleLogin = async (e) => {
        e.preventDefault();
        setLoading(true);
        setError('');

        const { error } = await supabase.auth.signInWithPassword({
            email,
            password,
        });

        if (error) {
            setError(error.message);
        } else {
            navigate('/admin/dashboard');
        }
        setLoading(false);
    };

    return (
        <div className="admin-login-container" style={{
            height: '100vh',
            display: 'flex',
            justifyContent: 'center',
            alignItems: 'center',
            background: 'var(--bg-color)',
            color: 'var(--text-primary)'
        }}>
            <motion.div
                className="login-box glass-panel"
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.5 }}
                style={{
                    background: 'rgba(255, 255, 255, 0.05)',
                    padding: '40px',
                    borderRadius: '16px',
                    border: '1px solid rgba(255,255,255,0.1)',
                    backdropFilter: 'blur(10px)',
                    width: '100%',
                    maxWidth: '400px',
                    boxShadow: '0 0 30px rgba(0, 240, 255, 0.1)'
                }}
            >
                <h2 style={{ fontFamily: 'var(--font-heading)', textAlign: 'center', marginBottom: '30px', color: 'var(--accent-color)' }}>
                    ADMIN ACCESS
                </h2>

                {error && <p style={{ color: '#ff4444', marginBottom: '15px', textAlign: 'center', fontSize: '0.9rem' }}>{error}</p>}

                <form onSubmit={handleLogin} style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                        <label style={{ fontSize: '0.9rem', color: 'var(--text-secondary)' }}>Operator Email</label>
                        <input
                            type="email"
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            required
                            className="input-field"
                            style={{
                                background: 'rgba(0,0,0,0.5)',
                                border: '1px solid rgba(255,255,255,0.2)',
                                padding: '12px',
                                color: 'white',
                                outline: 'none',
                                borderRadius: '8px',
                                transition: 'border-color 0.3s'
                            }}
                        />
                    </div>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                        <label style={{ fontSize: '0.9rem', color: 'var(--text-secondary)' }}>Passcode</label>
                        <input
                            type="password"
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            required
                            className="input-field"
                            style={{
                                background: 'rgba(0,0,0,0.5)',
                                border: '1px solid rgba(255,255,255,0.2)',
                                padding: '12px',
                                color: 'white',
                                outline: 'none',
                                borderRadius: '8px',
                                transition: 'border-color 0.3s'
                            }}
                        />
                    </div>

                    <button
                        type="submit"
                        disabled={loading}
                        style={{
                            padding: '15px',
                            background: 'var(--accent-color)',
                            color: '#000',
                            border: 'none',
                            borderRadius: '8px',
                            fontFamily: 'var(--font-heading)',
                            fontWeight: 'bold',
                            cursor: loading ? 'not-allowed' : 'pointer',
                            marginTop: '10px',
                            transition: 'all 0.3s'
                        }}
                    >
                        {loading ? 'AUTHENTICATING...' : 'AUTHORIZE'}
                    </button>
                </form>
            </motion.div>
        </div>
    );
};

export default AdminLogin;

